// TestSilencesBulkSuccessfulCreation tests successful creation of multiple silences.
func TestSilencesBulkSuccessfulCreation(t *testing.T) {
	req := BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []Matcher{
					{Name: "job", Value: "prometheus", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Maintenance window",
			},
			{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(2 * time.Hour),
				CreatedBy: "user",
				Comment:   "Silencing test alert",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	httpReq.Header.Set("Content-Type", "application/json")

	api := &API{}
	result := api.silencesBulk(httpReq)

	require.NoError(t, result.err)
	require.NotNil(t, result.data)

	resp, ok := result.data.(*BulkSilenceResponse)
	require.True(t, ok, "expected BulkSilenceResponse")
	require.Equal(t, 2, len(resp.SilenceIDs))

	// Verify that IDs are non-empty and unique
	for _, id := range resp.SilenceIDs {
		require.NotEmpty(t, id)
	}
	require.NotEqual(t, resp.SilenceIDs[0], resp.SilenceIDs[1])
}

