// TestSilenceValidator tests the Silence validation logic.
func TestSilenceValidator(t *testing.T) {
	testCases := []struct {
		name    string
		silence Silence
		isValid bool
		errorMsg string
	}{
		{
			name: "valid silence",
			silence: Silence{
				Matchers: []Matcher{
					{Name: "job", Value: "test", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Test",
			},
			isValid: true,
		},
		{
			name: "no matchers",
			silence: Silence{
				Matchers:  []Matcher{},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "admin",
				Comment:   "Test",
			},
			isValid: false,
			errorMsg: "matchers must not be empty",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			err := tc.silence.Validate()
			if tc.isValid {
				require.NoError(t, err)
			} else {
				require.Error(t, err)
				require.Contains(t, err.Error(), tc.errorMsg)
			}
		})
	}
}

// TestMatcherValidator tests the Matcher validation logic.
func TestMatcherValidator(t *testing.T) {
	testCases := []struct {
		name    string
		matcher Matcher
		isValid bool
		errorMsg string
	}{
		{
			name:    "valid simple matcher",
			matcher: Matcher{Name: "job", Value: "test", IsRegex: false},
			isValid: true,
		},
		{
			name:    "valid regex matcher",
			matcher: Matcher{Name: "alertname", Value: "TestAlert.*", IsRegex: true},
			isValid: true,
		},
		{
			name:    "empty name",
			matcher: Matcher{Name: "", Value: "test", IsRegex: false},
			isValid: false,
			errorMsg: "matcher name must not be empty",
		},
		{
			name:    "invalid regex",
			matcher: Matcher{Name: "job", Value: "[invalid", IsRegex: true},
			isValid: false,
			errorMsg: "regex",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			err := tc.matcher.Validate()
			if tc.isValid {
				require.NoError(t, err)
			} else {
				require.Error(t, err)
				if tc.errorMsg != "" {
					require.Contains(t, err.Error(), tc.errorMsg)
				}
			}
		})
	}
}

